package processing.org.apache.carbondata.processing.loading.csvinput;

public class BlockDetails extends FileSplit implements Serializable { private static final long serialVersionUID = 2293906691860002339L ; private long blockOffset ; private long blockLength ; private String filePath ; private String [ ] locations ; public BlockDetails ( Path filePath , long blockOffset , long blockLength , String [ ] locations ) { super ( filePath , blockOffset , blockLength , locations ) ; this . filePath = filePath . toString ( ) ; this . blockOffset = blockOffset ; this . blockLength = blockLength ; this . locations = locations ; } public long getBlockOffset ( ) { return blockOffset ; } public long getBlockLength ( ) { return blockLength ; } public String getFilePath ( ) { return FileFactory . getUpdatedFilePath ( filePath ) ; } public void setFilePath ( String filePath ) { this . filePath = filePath ; } public String [ ] getLocations ( ) { return locations ; } @ Override public Path getPath ( ) { return new Path ( filePath ) ; } @ Override public long getStart ( ) { return blockOffset ; } @ Override public long getLength ( ) { return blockLength ; } }